#include <stdio.h>
#include <stdlib.h>

typedef struct {int idx; int val;} Node;

int main(){
    int *A=NULL,*B=NULL;
    int N;
    while (scanf("%d",&N)==1){
        A = (int*)realloc(A,N*sizeof(int));
        B = (int*)realloc(B,N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d %d",&A[i],&B[i]);
        // deques implemented with circular buffers
        int *dqMax = (int*)malloc(N*sizeof(int)); // indices for max A
        int *dqMin = (int*)malloc(N*sizeof(int)); // indices for min B
        int headMax=0, tailMax=0, headMin=0, tailMin=0;
        int l=0, ans=0;
        for(int r=0;r<N;r++){
            while(headMax<tailMax && A[dqMax[tailMax-1]]<=A[r]) tailMax--;
            dqMax[tailMax++] = r;
            while(headMin<tailMin && B[dqMin[tailMin-1]]>=B[r]) tailMin--;
            dqMin[tailMin++] = r;
            while(l<=r){
                int maxA = A[dqMax[headMax]];
                int minB = B[dqMin[headMin]];
                int win = r-l+1;
                if(minB - maxA + 1 >= win) break;
                if(dqMax[headMax]==l) headMax++;
                if(dqMin[headMin]==l) headMin++;
                l++;
            }
            int win = r-l+1;
            if(win>ans) ans=win;
        }
        printf("%d\n",ans);
        free(dqMax); free(dqMin);
    }
    free(A); free(B);
    return 0;
}

