import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        while (fs.hasNext()) {
            int N = fs.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = fs.nextInt();
                B[i] = fs.nextInt();
            }
            Deque<Integer> maxA = new ArrayDeque<>();
            Deque<Integer> minB = new ArrayDeque<>();
            int l = 0, ans = 0;
            for (int r = 0; r < N; r++) {
                while (!maxA.isEmpty() && A[maxA.peekLast()] <= A[r]) maxA.pollLast();
                maxA.addLast(r);
                while (!minB.isEmpty() && B[minB.peekLast()] >= B[r]) minB.pollLast();
                minB.addLast(r);
                while (l <= r) {
                    int curMaxA = A[maxA.peekFirst()];
                    int curMinB = B[minB.peekFirst()];
                    int win = r - l + 1;
                    if (curMinB - curMaxA + 1 >= win) break;
                    if (maxA.peekFirst() == l) maxA.pollFirst();
                    if (minB.peekFirst() == l) minB.pollFirst();
                    l++;
                }
                ans = Math.max(ans, r - l + 1);
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        boolean hasNext() throws IOException {
            int c;
            while ((c = readByte()) != -1) {
                if (!Character.isWhitespace(c)) { ptr--; return true; }
            }
            return false;
        }
        int nextInt() throws IOException { int c; while ((c = readByte()) <= ' ') ; int sign = 1; if (c == '-') { sign = -1; c = readByte(); } int val = 0; while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); } return val * sign; }
    }
}

