#!/usr/bin/env python3
import sys
from collections import deque

def solve_one(N, A, B):
    maxA = deque()
    minB = deque()
    l = 0
    ans = 0
    for r in range(N):
        while maxA and A[maxA[-1]] <= A[r]:
            maxA.pop()
        maxA.append(r)
        while minB and B[minB[-1]] >= B[r]:
            minB.pop()
        minB.append(r)
        while l <= r:
            cur_max = A[maxA[0]]
            cur_min = B[minB[0]]
            win = r - l + 1
            if cur_min - cur_max + 1 >= win:
                break
            if maxA[0] == l:
                maxA.popleft()
            if minB[0] == l:
                minB.popleft()
            l += 1
        ans = max(ans, r - l + 1)
    return ans

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    idx = 0
    out_lines = []
    while idx < len(data):
        N = int(data[idx]); idx += 1
        A = [0]*N
        B = [0]*N
        for i in range(N):
            A[i] = int(data[idx]); B[i] = int(data[idx+1]); idx += 2
        out_lines.append(str(solve_one(N, A, B)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

